import{_ as a,c as n,o as t,ag as i}from"./chunks/framework.IQH0tUiJ.js";const u=JSON.parse('{"title":"WebUI Handlers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/handlers/index.md","filePath":"guide/concepts/handlers/index.md"}'),r={name:"guide/concepts/handlers/index.md"};function o(l,e,s,d,c,h){return t(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="webui-handlers" tabindex="-1">WebUI Handlers <a class="header-anchor" href="#webui-handlers" aria-label="Permalink to &quot;WebUI Handlers&quot;">​</a></h1><p>WebUI handlers are the bridge between the WebUI protocol and the final rendered HTML output. They process the protocol and render the content in a specific programming language.</p><h2 id="available-handlers" tabindex="-1">Available Handlers <a class="header-anchor" href="#available-handlers" aria-label="Permalink to &quot;Available Handlers&quot;">​</a></h2><p>WebUI provides official handlers for several popular programming languages (other languages coming soon):</p><ul><li><a href="./rust.html"><strong>Rust</strong></a> - High-performance native rendering with the Rust programming language</li><li><a href="./node.html"><strong>Node.js</strong></a> - Streaming SSR via a native addon built with napi-rs</li><li><a href="./wasm.html"><strong>WebAssembly</strong></a> - In-browser rendering for playgrounds and client-side use</li><li><a href="./ffi.html"><strong>FFI (C API)</strong></a> - Shared library for Go, C#, Python, and any language with C interop</li></ul><h2 id="how-handlers-work" tabindex="-1">How Handlers Work <a class="header-anchor" href="#how-handlers-work" aria-label="Permalink to &quot;How Handlers Work&quot;">​</a></h2><p>All WebUI handlers follow the same pattern:</p><ol><li>They accept a WebUI protocol object (parsed from protobuf binary)</li><li>They process the protocol with the provided state data</li><li>They render the final HTML output by evaluating directives and inserting dynamic content</li></ol><p>This consistent approach ensures that the same template produces identical results across different programming languages and platforms.</p><h2 id="common-handler-interface" tabindex="-1">Common Handler Interface <a class="header-anchor" href="#common-handler-interface" aria-label="Permalink to &quot;Common Handler Interface&quot;">​</a></h2><p>While the specific implementation details vary between languages, all handlers provide a similar API:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>handle(protocol, state, writer)</span></span></code></pre></div><p>Where:</p><ul><li><code>protocol</code> is the WebUI protocol object</li><li><code>state</code> is the data object with values to be rendered</li><li><code>writer</code> is a callback or interface for writing the rendered output</li></ul><h2 id="plugin-system" tabindex="-1">Plugin System <a class="header-anchor" href="#plugin-system" aria-label="Permalink to &quot;Plugin System&quot;">​</a></h2><p>Handlers support an optional <strong>plugin system</strong> for injecting framework-specific behavior during rendering. Plugins receive lifecycle callbacks at key points — binding start/end, loop iteration, scope changes — and can write additional content to the output.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>handler = Handler::with_plugin(plugin)</span></span>
<span class="line"><span>handler.handle(protocol, state, writer)</span></span></code></pre></div><p>When no plugin is configured, the handler renders plain HTML. When a plugin is loaded (e.g., <code>FastHydrationPlugin</code>), it injects markers that enable client-side hydration.</p><p>See <a href="/guide/concepts/plugins/">Plugins</a> for the full plugin API and built-in plugins.</p><h2 id="handler-customization" tabindex="-1">Handler Customization <a class="header-anchor" href="#handler-customization" aria-label="Permalink to &quot;Handler Customization&quot;">​</a></h2><p>Each handler implementation can be extended or customized to fit specific requirements. See the individual handler documentation for language-specific details.</p>`,21)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
